#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Table;

# Our brave script to extract the date, author, and table information from a PDF
sub extract_info {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Loop through each page to find the date, author, and table
    for my $page (1 .. $pdf->pages) {
        my $text = $pdf->page($page)->extract_contents();

        # Extract date (assuming it's in the format "Date: October 1, 2023")
        if ($text =~ /Date:\s+([\w\s,]+)\s+\d{4}/) {
            print "Date: $1\n";
        }

        # Extract author (assuming it's in the format "Author: John Doe")
        if ($text =~ /Author:\s+([\w\s]+)/) {
            print "Author: $1\n";
        }

        # Extract table (assuming it's in the format of a simple text table)
        if ($text =~ /Table\s+information:/) {
            my $table_text = $text;
            $table_text =~ s/.*Table\s+information://;
            $table_text =~ s/\/.*//; # Remove any trailing slashes or text
            print "Table Information:\n";
            print $table_text;
        }
    }
}

# Usage example
extract_info('example.pdf');
